    async def _execute_trade(self, trade: Dict) -> bool:
        """Execute a trade between two players"""
        try:
            # Use locks to prevent race conditions
            locks = []
            for item_id in trade['items_offered']:
                lock = self.item_locks.get(item_id, asyncio.Lock())
                self.item_locks[item_id] = lock
                locks.append(lock)
                
            for item_id in trade['items_requested']:
                lock = self.item_locks.get(item_id, asyncio.Lock())
                self.item_locks[item_id] = lock
                locks.append(lock)
                
            # Acquire all locks
            await asyncio.gather(*[lock.acquire() for lock in locks])
            
            # Validate items are still available
            if not self._validate_items(trade['items_offered'], trade['initiator']) or not self._validate_items(trade['items_requested'], trade['target']):
                return False
                
            # Perform the actual transfer
            for item_data in trade['items_offered']:
                await self._perform_item_transfer(trade['initiator'], trade['target'], item_data['id'], item_data['quantity'])
                
            for item_data in trade['items_requested']:
                await self._perform_item_transfer(trade['target'], trade['initiator'], item_data['id'], item_data['quantity'])
                
            return True
            
        except Exception as e:
            self.logger.error(f"Trade execution error: {e}")
            return False
        finally:
            # Release all locks
            for lock in locks:
                if lock.locked():
                    lock.release()
    
    async def _perform_item_transfer(self, from_player_id: str, to_player_id: str, item_id: str, quantity: int) -> bool:
        """Perform item transfer with atomic operations"""
        try:
            from_player = self.players.get(from_player_id)
            to_player = self.players.get(to_player_id)
            
            if not from_player or not to_player:
                return False
                
            # Get item from source player
            item = from_player.inventory.get(item_id)
            if not item or item.quantity < quantity:
                return False
                
            # Update source player
            if item.quantity == quantity:
                del from_player.inventory[item_id]
            else:
                item.quantity -= quantity
                
            # Update target player
            if item_id in to_player.inventory:
                to_player.inventory[item_id].quantity += quantity
            else:
                # Create new item for target player
                new_item = Item(
                    id=item_id,
                    name=item.name,
                    item_type=item.item_type,
                    quantity=quantity,
                    owner_id=to_player_id,
                    metadata=item.metadata.copy()
                )
                to_player.inventory[item_id] = new_item
                
            return True
            
        except Exception as e:
            self.logger.error(f"Item transfer error: {e}")
            return False
    
    def _validate_items(self, items: List[Dict], player_id: str) -> bool:
        """Validate that items exist and are owned by player"""
        player = self.players.get(player_id)
        if not player:
            return False
            
        for item_data in items:
            item_id = item_data.get('id')
            quantity = item_data.get('quantity', 1)
            
            if item_id not in player.inventory:
                return False
                
            item = player.inventory[item_id]
            if item.quantity < quantity:
                return False
                
        return True
    
